namespace RecipeShare.Data;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public static class RecipeStore
{
    private static readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices.", "Dice tomatoes and mix with basil and garlic.", "Top bread with tomato mixture and drizzle with olive oil."],
            AverageRating = 4.2, RatingCount = 5
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
            Steps = ["Remove mushroom stems.", "Mix filling ingredients.", "Stuff caps and bake at 375°F for 20 minutes."],
            AverageRating = 4.5, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Eggs", "Pecorino cheese", "Pancetta", "Black pepper"],
            Steps = ["Cook pasta al dente.", "Fry pancetta until crisp.", "Mix eggs and cheese.", "Toss hot pasta with pancetta, then stir in egg mixture off heat."],
            AverageRating = 4.8, RatingCount = 12
        },
        new()
        {
            Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Yogurt", "Tikka spice mix", "Tomato sauce", "Cream", "Rice"],
            Steps = ["Marinate chicken in yogurt and spices.", "Grill chicken pieces.", "Simmer tomato sauce with cream.", "Add chicken to sauce and serve over rice."],
            AverageRating = 4.6, RatingCount = 10
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter.", "Whisk eggs and sugar, fold in chocolate mixture and flour.", "Bake at 425°F for 12 minutes.", "Invert onto plate and serve immediately."],
            AverageRating = 4.9, RatingCount = 15
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Eggs", "Sugar", "Cocoa powder"],
            Steps = ["Dip ladyfingers in espresso.", "Beat egg yolks with sugar, fold in mascarpone.", "Layer soaked ladyfingers and cream.", "Refrigerate 4 hours and dust with cocoa."],
            AverageRating = 4.7, RatingCount = 9
        }
    ];

    public static IReadOnlyList<Recipe> GetAll() => _recipes;

    public static IReadOnlyList<Recipe> GetByCategory(string categorySlug) =>
        _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public static Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public static void Add(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public static void SetRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = (totalStars + stars) / recipe.RatingCount;
    }
}

@page "/recipes/{CategorySlug}"
@using RecipeShare.Data

<PageTitle>@categoryName Recipes - RecipeShare</PageTitle>

<h1>@categoryName</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="list-group">
        @foreach (var recipe in recipes)
        {
            <a href="/recipe/@recipe.Id" class="list-group-item list-group-item-action">
                <div class="d-flex w-100 justify-content-between">
                    <h5 class="mb-1">@recipe.Title</h5>
                    <small>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</small>
                </div>
                <p class="mb-1">@string.Join(", ", recipe.Ingredients.Take(4))@(recipe.Ingredients.Count > 4 ? "..." : "")</p>
            </a>
        }
    </div>
}

<div class="mt-3">
    <a href="/" class="btn btn-outline-secondary">← Back to Categories</a>
</div>

@code {
    [Parameter] public string CategorySlug { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = [];
    private string categoryName = string.Empty;

    protected override void OnParametersSet()
    {
        recipes = RecipeStore.GetByCategory(CategorySlug);
        categoryName = recipes.Count > 0 ? recipes[0].Category : CategorySlug;
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Data

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p><span class="badge bg-secondary">@recipe.Category</span></p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="recipe.Id" />

    <div class="mt-4">
        <a href="/recipes/@recipe.CategorySlug" class="btn btn-outline-secondary">← Back to @recipe.Category</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeStore.GetById(Id);
    }
}

@using RecipeShare.Data
@rendermode InteractiveServer

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <div class="d-inline-block ms-2" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  class="@(star <= (hoverStar > 0 ? hoverStar : selectedStar) ? "text-warning" : "text-muted")">
                ★
            </span>
        }
    </div>
    @if (submitted)
    {
        <div class="alert alert-success mt-2" role="alert">
            Thanks! You rated this @selectedStar out of 5 stars.
        </div>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int hoverStar;
    private int selectedStar;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedStar = stars;
        RecipeStore.SetRating(RecipeId, stars);
        submitted = true;
    }
}

@page "/submit"
@using RecipeShare.Data
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success" role="alert">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="model.Title" class="form-control" />
        <ValidationMessage For="() => model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Appetizers">Appetizers</option>
            <option value="Main Courses">Main Courses</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="model.IngredientsText" class="form-control" rows="5" />
        <ValidationMessage For="() => model.IngredientsText" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="model.StepsText" class="form-control" rows="5" />
        <ValidationMessage For="() => model.StepsText" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var categorySlug = model.Category.ToLowerInvariant().Replace(" ", "-");

        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            CategorySlug = categorySlug,
            Ingredients = model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeStore.Add(recipe);
        successMessage = $"'{recipe.Title}' has been submitted successfully!";
        model = new();
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Data;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one ingredient.")]
    [MinLength(3, ErrorMessage = "Please enter at least one ingredient.")]
    public string IngredientsText { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one step.")]
    [MinLength(3, ErrorMessage = "Please enter at least one step.")]
    public string StepsText { get; set; } = string.Empty;
}

