@page "/recipe/{Id:int}"
@using RecipeShare.Data

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p><span class="badge bg-secondary">@recipe.Category</span></p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="recipe.Id" />

    <div class="mt-4">
        <a href="/recipes/@recipe.CategorySlug" class="btn btn-outline-secondary">← Back to @recipe.Category</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeStore.GetById(Id);
    }
}

@using RecipeShare.Data
@rendermode InteractiveServer

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <div class="d-inline-block ms-2" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  class="@(star <= (hoverStar > 0 ? hoverStar : selectedStar) ? "text-warning" : "text-muted")">
                ★
            </span>
        }
    </div>
    @if (submitted)
    {
        <div class="alert alert-success mt-2" role="alert">
            Thanks! You rated this @selectedStar out of 5 stars.
        </div>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int hoverStar;
    private int selectedStar;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedStar = stars;
        RecipeStore.SetRating(RecipeId, stars);
        submitted = true;
    }
}

