toolArgs.file_text:
@page "/submit"
@using RecipeShare.Data
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success" role="alert">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="model.Title" class="form-control" />
        <ValidationMessage For="() => model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Appetizers">Appetizers</option>
            <option value="Main Courses">Main Courses</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="model.IngredientsText" class="form-control" rows="5" />
        <ValidationMessage For="() => model.IngredientsText" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="model.StepsText" class="form-control" rows="5" />
        <ValidationMessage For="() => model.StepsText" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var categorySlug = model.Category.ToLowerInvariant().Replace(" ", "-");

        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            CategorySlug = categorySlug,
            Ingredients = model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeStore.Add(recipe);
        successMessage = $"'{recipe.Title}' has been submitted successfully!";
        model = new();
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Data;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one ingredient.")]
    [MinLength(3, ErrorMessage = "Please enter at least one ingredient.")]
    public string IngredientsText { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter at least one step.")]
    [MinLength(3, ErrorMessage = "Please enter at least one step.")]
    public string StepsText { get; set; } = string.Empty;
}

